 1→import { GRID_MINOR } from '@/domain/defaults';
 2→import { createStair } from '@/domain/models';
 3→import { distance } from '@/geometry/point';
 4→
 5→function snapToGrid(value) {
 6→  return Math.round(value / GRID_MINOR) * GRID_MINOR;
 7→}
 8→
 9→function getAngleDegrees(startPoint, endPoint) {
10→  return (Math.atan2(endPoint.y - startPoint.y, endPoint.x - startPoint.x) * 180) / Math.PI;
11→}
12→
13→function resolvePoint(modelPos, snapEnabled) {
14→  if (!snapEnabled) return { x: modelPos.x, y: modelPos.y };
15→  return {
16→    x: snapToGrid(modelPos.x),
17→    y: snapToGrid(modelPos.y),
18→  };
19→}
20→
21→function resetStairTool(editorDispatch) {
22→  editorDispatch({
23→    type: 'UPDATE_TOOL_STATE',
24→    payload: {
25→      stairStartPoint: null,
26→      stairPreviewPoint: null,
27→      stairPreviewAngle: null,
28→    },
29→  });
30→}
31→
32→export function createStairPlaceHandler({ dispatch, editorDispatch, activeFloorId, snapEnabled }) {
33→  return {
34→    onMouseDown(modelPos, e, toolState) {
35→      if (e.button !== 0) return;
36→
37→      const point = resolvePoint(modelPos, snapEnabled);
38→
39→      if (!toolState.stairStartPoint) {
40→        editorDispatch({
41→          type: 'UPDATE_TOOL_STATE',
42→          payload: {
43→            stairStartPoint: point,
44→            stairPreviewPoint: point,
45→            stairPreviewAngle: 0,
46→          },
47→        });
48→        editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Click again to set stair direction.' });
49→        return;
50→      }
51→
52→      if (distance(toolState.stairStartPoint, point) < GRID_MINOR / 2) {
53→        editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Choose a direction farther from the stair start.' });
54→        return;
55→      }
56→
57→      const stair = createStair(
58→        toolState.stairStartPoint,
59→        undefined,
60→        undefined,
61→        undefined,
62→        undefined,
63→        { angle: getAngleDegrees(toolState.stairStartPoint, point) },
64→        { fromFloorId: activeFloorId, toFloorId: activeFloorId }
65→      );
66→
67→      dispatch({ type: 'STAIR_ADD', floorId: activeFloorId, stair });
68→      editorDispatch({ type: 'SELECT_OBJECT', id: stair.id, objectType: 'stair' });
69→      resetStairTool(editorDispatch);
70→      editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Stair created.' });
71→    },
72→
73→    onMouseMove(modelPos, e, toolState) {
74→      if (!toolState.stairStartPoint) return;
75→      const point = resolvePoint(modelPos, snapEnabled);
76→      editorDispatch({
77→        type: 'UPDATE_TOOL_STATE',
78→        payload: {
79→          stairPreviewPoint: point,
80→          stairPreviewAngle: getAngleDegrees(toolState.stairStartPoint, point),
81→        },
82→      });
83→    },
84→
85→    onKeyDown(e) {
86→      if (e.key !== 'Escape') return;
87→      resetStairTool(editorDispatch);
88→      editorDispatch({ type: 'SET_TOOL', tool: 'select' });
89→    },
90→
91→    getCursor() {
92→      return 'crosshair';
93→    },
94→  };
95→}
