113→function createStairDescriptor(stair, floorLevel, floorId) {
114→  const renderData = getStairRenderData(stair);
115→  if (!renderData?.outline?.length) return null;
116→
117→  return {
118→    id: stair.id,
119→    kind: 'stair',
120→    geometry: 'stair',
121→    startPoint: { ...stair.startPoint },
122→    width: stair.width,
123→    numberOfRisers: stair.numberOfRisers,
124→    riserHeight: stair.riserHeight,
125→    treadDepth: stair.treadDepth,
126→    angle: renderData.angle,
127→    baseElevation: floorLevel,
128→    materialKey: 'stair',
129→    metadata: {
130→      sourceId: stair.id,
131→      floorId,
132→    },
133→    bounds: createBoundsFromPoints(
134→      renderData.outline,
135→      floorLevel,
136→      floorLevel + renderData.totalRise
137→    ),
138→  };
139→}
