221→      DOOR_INSERT_THICKNESS_MIN,
222→      Math.min(wallThickness * 0.22, DOOR_INSERT_THICKNESS_MAX)
223→    );
224→  }
225→
226→  return Math.max(
227→    WINDOW_INSERT_THICKNESS_MIN,
228→    Math.min(wallThickness * 0.32, WINDOW_INSERT_THICKNESS_MAX)
229→  );
