253→function buildDoorObjects(wallContexts) {
254→  return wallContexts
255→    .flatMap((context) => context.openings)
256→    .filter((opening) => opening.kind === 'door')
257→    .map((opening) => createOpeningInsertDescriptor(opening));
258→}
