260→function buildWindowObjects(wallContexts) {
261→  return wallContexts
262→    .flatMap((context) => context.openings)
263→    .filter((opening) => opening.kind === 'window')
264→    .map((opening) => {
265→      const desc = createOpeningInsertDescriptor(opening);
266→      desc.geometry = 'window';
267→      desc.windowType = opening.type || 'standard';
268→      desc.openDirection = opening.openDirection || 'left';
269→      return desc;
270→    });
