279→export function buildFloorPreviewObjects(floor) {
280→  const floorLevel = getFloorElevation(floor);
281→  const wallContexts = buildWallPreviewContexts(floor, floorLevel);
282→
283→  return [
284→    ...buildSlabObjects(floor),
285→    ...buildWallObjects(wallContexts),
286→    ...buildColumnObjects(floor, floorLevel),
287→    ...buildBeamObjects(floor),
288→    ...buildStairObjects(floor, floorLevel),
289→    ...buildDoorObjects(wallContexts),
290→    ...buildWindowObjects(wallContexts),
291→  ];
292→}
